import { SignJWT, jwtVerify, importPKCS8, importSPKI } from "jose";
import { readFileSync } from "node:fs";
const PRIVATE_KEY_PEM = readFileSync(process.env.JWT_PRIVATE_KEY_PATH!, "utf8");
const PUBLIC_KEY_PEM  = readFileSync(process.env.JWT_PUBLIC_KEY_PATH!,  "utf8");
export async function sign(payload: object) {
  const key = await importPKCS8(PRIVATE_KEY_PEM, "RS256");  // RS256
  return new SignJWT(payload as any).setProtectedHeader({ alg: "RS256" }).sign(key);
}
